text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "decisions": {
      "confirmed_decisions": [
        "공개 릴리스 목표는 스모크 테스트 통과 시 금요일 15:00 KST로 한다.",
        "packageName 불일치 발생 시 우선 패키지 설정(config)을 점검하고, 계약(컨트랙트) 자체가 잘못된 경우에만 smoke-theme-pack.mjs 스크립트를 검토한다."
      ],
      "rejected_proposals": [
        "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경하자는 제안은 기각되었다."
      ],
      "internal_stretch_goals": [
        "수요일 릴리스 제안은 내부 스트레치 목표이며 확정 공개 일정이 아니다."
      ]
    },
    "non_decisions": [
      "README 설치 단계 검토 필요성은 언급되었으나 담당자가 지정되지 않았다.",
      "Hara의 tarball 경로 확인은 수행하기로 했으나 정확한 기한은 정해지지 않았다."
    ],
    "risks": [
      "잘못된 tarball 경로는 릴리스 지연을 유발할 수 있다.",
      "README 설치 단계가 최신이 아니면 릴리스 노트가 사용자에게 오해를 줄 수 있다."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 스트레치 목표를 명시할 것인가?"
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 이후 생성된 tarball 경로 확인",
      "due": "정확한 기한 미정",
      "status": "선행 결과 대기",
      "source_certainty": "확정(기한 미확정)"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 검토",
      "due": "목요일 가능 시(확정 아님)",
      "status": "담당자 지정 필요",
      "source_certainty": "제안 수준(미확정)"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "금요일 10:00 KST 이후 Minjun의 스모크 테스트 결과 수신 여부",
      "스모크 결과 수신 직후 Hara의 tarball 경로 검증 결과",
      "금요일 12:00 KST까지 Doyun의 action_items.md 트리아지 노트 작성 완료 여부",
      "최종 릴리스 승인 권한자 지정",
      "README 검토 담당자 지정 및 반영 여부",
      "릴리스 노트에 내부 수요일 스트레치 목표를 포함할지 결정"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요건",
      "명시되지 않은 담당자/마감 시한"
    ]
  },
  "non_invention_rules": [
    "근거는 제공된 PUBLIC-SAFE SYNTHETIC MEETING FIXTURE에 한정한다.",
    "확정되지 않은 사항은 '미정', '미확정', '제안 수준'으로 표기한다.",
    "고객, 예산, 보안, 장애, 법무, 소유자, 마감 관련 신규 사실을 추가하지 않는다.",
    "결정/기각/스트레치 목표/리스크/오픈 질문을 혼합하지 않고 분리해 기록한다."
  ]
}
